import React, { useState } from "react";
import { useNavigate, Link } from "react-router-dom"; // Added Link
import { authAPI } from "./api";

function Login() {
  const navigate = useNavigate();
  
  const [formData, setFormData] = useState({
    email: "",
    password: "",
    language: "English"
  });
  
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      // This remains as authAPI.login because your api.js exports it that way
      const response = await authAPI.login({
        email: formData.email,
        password: formData.password
      });

      localStorage.setItem('token', response.data.token);
      localStorage.setItem('user', JSON.stringify(response.data.user));
      
      alert('Login Successful! Welcome ' + response.data.user.name);
      navigate('/');
      
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>Citizen Login</h2>
        <form onSubmit={handleLogin}>
          <input
            type="email"
            name="email"
            style={styles.input}
            placeholder="Email Address"
            value={formData.email}
            onChange={handleChange}
            required
          />
          <input
            type="password"
            name="password"
            style={styles.input}
            placeholder="Password"
            value={formData.password}
            onChange={handleChange}
            required
          />
          
          {error && <p style={{ color: "#ff4d4d", fontSize: "14px", marginBottom: "10px" }}>{error}</p>}
          
          <button 
            type="submit" 
            style={styles.button}
            disabled={loading}
          >
            {loading ? 'Logging in...' : 'Login'}
          </button>
        </form>
        
        <p style={styles.note}>
          Don't have an account? <Link to="/register" style={{color: "#6c63ff", textDecoration: "none", fontWeight: "bold"}}>Sign Up here</Link>
        </p>
      </div>
    </div>
  );
}

const styles = {
  container: {
    height: "100vh",
    backgroundColor: "#3a3a50",
    color: "#f0f0f0",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    alignItems: "center",
    fontFamily: "Arial, sans-serif",
  },
  card: {
    background: "rgba(255,255,255,0.1)",
    padding: "40px",
    borderRadius: "15px",
    boxShadow: "0 10px 30px rgba(0,0,0,0.5)",
    width: "350px"
  },
  title: { 
    fontSize: "2rem", 
    marginBottom: "20px",
    textAlign: "center"
  },
  input: {
    padding: "12px",
    width: "100%",
    borderRadius: "5px",
    border: "none",
    marginBottom: "15px",
    fontSize: "14px",
    boxSizing: "border-box"
  },
  button: {
    width: "100%",
    padding: "12px",
    backgroundColor: "#6c63ff",
    color: "white",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
    fontSize: "16px",
    fontWeight: "bold"
  },
  note: {
    marginTop: "20px",
    textAlign: "center",
    fontSize: "14px",
    color: "#ccc"
  }
};

export default Login;
